  CLASS
	NAME "Modelo MIHR - Escenario A1B"
    EXPRESSION ([pixel] = -99999)
    COLOR -1 -1 -1
  END
  CLASS
	NAME " "
    EXPRESSION ([pixel] = -9999)
    COLOR -1 -1 -1
  END
  CLASS
	NAME "Anomalía de pp (%)"
    EXPRESSION ([pixel] = -999)
    COLOR -1 -1 -1
  END
  CLASS
	NAME "-7.7 - -6"
    EXPRESSION ([pixel] >= -7.7 AND [pixel] < -6)
    COLOR 243 255 20
  END
  CLASS
	NAME "-6 - -5"
    EXPRESSION ([pixel] >= -6 AND [pixel] < -5)
    COLOR 208 240 0
  END
  CLASS
	NAME "-5 - -4"
    EXPRESSION ([pixel] >= -5 AND [pixel] < -4)
    COLOR 0 255 0
  END
  CLASS
	NAME "-4 - -3"
    EXPRESSION ([pixel] >= -4 AND [pixel] < -3)
    COLOR 44 150 69
  END
  CLASS
	NAME "-3 - -2"
    EXPRESSION ([pixel] >= -3 AND [pixel] < -2)
    COLOR 80 196 51
  END
  CLASS
	NAME "-2 - -1"
    EXPRESSION ([pixel] >= -2 AND [pixel] < -1)
    COLOR 25 230 168
  END
  CLASS
	NAME "-1 - -0.5"
    EXPRESSION ([pixel] >= -11.5 AND [pixel] < -0.5)
    COLOR 0 168 132
  END
  CLASS
	NAME "-0.5 - 0.7"
    EXPRESSION ([pixel] >= -0.5 AND [pixel] <= 0.7)
    COLOR 41 248 255
  END
